---@class LxPreloadTData
local LxPreloadTData = classX("LxPreloadTData", nil)
function LxPreloadTData:LxPreloadTData()
    self.assetPath = nil -- 资源路径
    self.assetType = nil --资源类型 C# Type typeof(object)
    self.loadType = nil --资源使用的加载函数 AssetLoadType
end

---@class LxPreloadTask
local LxPreloadTask = classX("LxPreloadTask", nil)

local TASK_LIMIT_COUNT = 4

local InvokeCallback = InvokeCallback

local AssetLoadType = AssetLoadType

local PreloadState = {
    Stop = 0,
    Running = 1
}

function LxPreloadTask:Initialize()

    self._loadState = PreloadState.Stop

    ---@type LxResRequester[]
    self._resRequesterList = {}
end

function LxPreloadTask:Dispose()

    self:ClearResRequesters()

    self._loadedOk = nil
    self._cbProcess = nil
    self._cbObject = nil
    self._dataList = nil
    self._loadState = PreloadState.Stop
end

function LxPreloadTask:ClearResRequesters()
    if not self._resRequesterList then return end
    if #self._resRequesterList == 0 then return end

    for k,v in ipairs(self._resRequesterList) do
        v:Dispose()
    end
    self._resRequesterList = {}
end


function LxPreloadTask:InitPreload(loadedOk, cbProcess, cbObj)
    if self._loadState ~= PreloadState.Stop then return end
    self._loadedOk = loadedOk
    self._cbProcess = cbProcess
    self._cbObject = cbObj

    self:ClearResRequesters()

    ---@type LxPreloadTData[]
    self._dataList = {}
end

---@param assetPath string @资源路径
---@param assetType Type @资源类型 C# Type typeof(object)
function LxPreloadTask:AddLoadAllAssets(assetPath, assetType)
    self:AddLoadData(assetPath, assetType, AssetLoadType.AllAssets)
end

---@param assetPath string @资源路径
---@param assetType Type @资源类型 C# Type typeof(object)
function LxPreloadTask:AddLoadSubAssets(assetPath, assetType)
    self:AddLoadData(assetPath, assetType, AssetLoadType.SubAssets)
end

---@param assetPath string @资源路径
---@param assetType Type @资源类型 C# Type typeof(object)
function LxPreloadTask:AddLoadAsset(assetPath, assetType)
    self:AddLoadData(assetPath, assetType, AssetLoadType.Asset)
end

---@param assetPath string @资源路径
---@param assetType Type @资源类型 C# Type typeof(object)
---@param loadType number @AssetLoadType
function LxPreloadTask:AddLoadData(assetPath, assetType, loadType)
    if self._loadState ~= PreloadState.Stop then return end
    local data =  LxPreloadTData:New()
    data.assetPath = assetPath
    data.assetType = assetType
    data.loadType = loadType
    table.insert(self._dataList, data)
end

function LxPreloadTask:StartPreload()
    if self._loadState == PreloadState.Stop then
        self._loadState = PreloadState.Running
        self._refIndex = 0
        self._refCount = #self._dataList
        self._loadCount = 0
        self._taskCount = 0

        if self._refCount == 0 then
            if LOG_INFO_ENABLED then
                printInfo("preload", "not preload data , Finished Preload Immediate!!!");
            end
            self:OnLoadOk()
            return
        end

        for _k=1, TASK_LIMIT_COUNT do
            self:LoadNext()
        end
    end
end

function LxPreloadTask:LoadNext()
    if self._isDisposed then return end

    if self._loadCount >= self._refCount then
        return
    end
    if self._taskCount >= TASK_LIMIT_COUNT then
        return
    end

    self._loadCount = self._loadCount + 1
    local data = table.remove(self._dataList, 1)
    self._taskCount = self._taskCount + 1

    ---@type LxResRequester
    local requester = nil

    if data.loadType == AssetLoadType.SubAssets then
        requester = LxResUtil.GetSubAssetsRequester(data.assetPath, data.assetType, function(objs)
            if self._isDisposed then return end
            if objs == nil then
                LogError("ProLoad asset error ... name:" ..tostring(data.assetPath))
            end
            self:OnLoadSingleOk()
        end)
    elseif data.loadType == AssetLoadType.AllAssets then
        requester = LxResUtil.GetAllAssetsRequester(data.assetPath, data.assetType, function(objs)
            if self._isDisposed then return end
            if objs == nil then
                LogError("ProLoad asset error ... name:" ..tostring(data.assetPath))
            end
            self:OnLoadSingleOk()
        end)
    else
        requester = LxResUtil.GetAssetRequester(data.assetPath, data.assetType, function(obj)
            if self._isDisposed then return end
            if obj == nil then
                LogError("ProLoad asset error ... name:" ..tostring(data.assetPath))
            end
            self:OnLoadSingleOk()
        end)
    end
    table.insert(self._resRequesterList, requester)
    requester:StartRequester()
end

function LxPreloadTask:OnLoadSingleOk()
    self._taskCount = self._taskCount - 1
    self._refIndex = self._refIndex + 1

    if self._cbProcess then
        InvokeCallback(self._cbProcess, self._cbObject, self._refIndex, self._refCount)
    end

    if self._refIndex >= self._refCount then
        if LOG_INFO_ENABLED then
            printInfo("preload", "Finished Preload !!!");
        end
        self:OnLoadOk()
    elseif self._loadCount < self._refCount then
        self:LoadNext()
    end
end

function LxPreloadTask:OnLoadOk()
    local loadedOk = self._loadedOk
    local cbObject = self._cbObject

    self._loadedOk = nil
    self._cbProcess = nil
    self._cbObject = nil
    self._dataList = nil
    self._loadState = PreloadState.Stop

    if loadedOk ~= nil then
        InvokeCallback(loadedOk, cbObject)
    end
end

return LxPreloadTask